import{_ as e,o as s,c as i,a2 as a}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"What is DSO?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-dso.md","filePath":"guide/what-is-dso.md"}'),o={name:"guide/what-is-dso.md"};function r(n,t,l,d,h,c){return s(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="what-is-dso" tabindex="-1">What is DSO? <a class="header-anchor" href="#what-is-dso" aria-label="Permalink to &quot;What is DSO?&quot;">​</a></h1><p><strong>Docker Secret Operator (DSO)</strong> is a native Docker CLI plugin that injects secrets from cloud vaults (AWS, Azure, HashiCorp Vault, Huawei CSMS) directly into your Docker containers at runtime — without <code>.env</code> files, without hardcoded credentials, and without Kubernetes.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Every Docker team eventually hits the same wall:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># The .env way — a security disaster</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DB_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-super-secret-password-123</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # sitting on every developer laptop</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sk-prod-abcdef</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # accidentally committed to GitHub</span></span></code></pre></div><p>The &quot;proper&quot; solution is Kubernetes with external-secrets — but that&#39;s months of migration and massive operational overhead for teams running Docker Compose stacks.</p><p><strong>DSO solves this without leaving Docker.</strong></p><h2 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">​</a></h2><p>DSO runs as a native Docker Engine plugin (<code>~/.docker/cli-plugins/docker-dso</code>). When you run <code>docker dso up -d</code>, it:</p><ol><li>Reads your <code>dso.yaml</code> to know which secrets to fetch and from where</li><li>Authenticates to your cloud vault using machine identity (IAM role, Managed Identity, Vault token)</li><li>Fetches secrets and holds them <strong>in memory only</strong> — nothing written to disk</li><li>Injects secrets into containers via the Docker Unix socket</li><li>Starts a background <strong>Watcher Engine</strong> that monitors for secret changes and rotates automatically</li></ol><h2 id="key-properties" tabindex="-1">Key Properties <a class="header-anchor" href="#key-properties" aria-label="Permalink to &quot;Key Properties&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Runtime only</strong></td><td>Secrets exist only while your stack is running</td></tr><tr><td><strong>Memory-only</strong></td><td>Never written to disk, not visible in <code>docker inspect</code></td></tr><tr><td><strong>Zero manual credentials</strong></td><td>Uses cloud-native identity (IAM, Managed Identity)</td></tr><tr><td><strong>Multi-cloud</strong></td><td>AWS, Azure, HashiCorp Vault, Huawei CSMS</td></tr><tr><td><strong>Docker-native</strong></td><td>First-class <code>docker dso</code> CLI subcommand</td></tr><tr><td><strong>Auto-rotation</strong></td><td>Detects secret changes and rotates containers intelligently</td></tr></tbody></table><h2 id="who-is-it-for" tabindex="-1">Who Is It For? <a class="header-anchor" href="#who-is-it-for" aria-label="Permalink to &quot;Who Is It For?&quot;">​</a></h2><ul><li><strong>DevOps engineers</strong> who need SOC2 compliance without migrating to Kubernetes</li><li><strong>Startups</strong> running production workloads on Docker Compose</li><li><strong>Security teams</strong> eliminating <code>.env</code> files from developer machines</li><li><strong>Platform engineers</strong> building a multi-cloud secret management layer</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/getting-started.html">Get Started in 5 minutes →</a></li><li><a href="/docs/guide/concepts.html">Understand the internals →</a></li><li><a href="/docs/guide/configuration.html">View configuration reference →</a></li></ul>`,16)])])}const g=e(o,[["render",r]]);export{p as __pageData,g as default};
